const msg = $input.first().json.message.text;
const today = new Date().toISOString().slice(0,10);

const prompt = `Sen ODIE, OdiePt fitness RPG kocusun. Kullanici mesajini analiz et ve JSON dondur.

Kullanici mesaji: ${msg}

Gorev: Mesajdan sunlari cikar:
1. date: YYYY-MM-DD formatinda tarih (belirtilmemisse bugun: ${today})
2. type: Push/Pull/Shoulder/Parkour/Akrobasi/Bacak/Yuruyus/Stretching/Custom
3. duration_min: dakika cinsinden sure (sayi)
4. highlight: kisa ozet metin (max 60 karakter)
5. exercises: [{name, sets:[{reps, weight_kg, duration_sec}]}]
6. coach_reply: Turkce kisa motivasyon (1-2 cumle, emoji olabilir)

Sadece gecerli JSON dondur, kod blogu kullanma, baska metin ekleme.`;

return [{ json: { prompt, userMessage: msg, today } }];

const raw = $input.first().json;
const text = raw.candidates[0].content.parts[0].text;
const parsed = JSON.parse(text);
return [{ json: parsed }];

const XP_BASE = { Push:100, Pull:100, Bacak:100, Parkour:120, Akrobasi:120, Shoulder:80, Stretching:60, Yuruyus:40, Custom:80 };
const parsed = $('Gemini Yaniti Isle').item.json;
const profile = $('Supabase Profile Oku').item.json;

const streakCurrent = profile.streak_current || 0;
const lastDate = profile.last_workout_date;
const today = parsed.date;

let newStreak = 1;
if (lastDate) {
  const dayDiff = Math.floor((new Date(today) - new Date(lastDate)) / 86400000);
  if (dayDiff === 0) newStreak = streakCurrent;
  else if (dayDiff === 1) newStreak = streakCurrent + 1;
  else if (dayDiff === 2) newStreak = streakCurrent;
  else newStreak = 1;
}

let mult = 1.0;
if (newStreak >= 30) mult = 2.0;
else if (newStreak >= 14) mult = 1.5;
else if (newStreak >= 7) mult = 1.25;
else if (newStreak >= 3) mult = 1.1;

const baseXp = XP_BASE[parsed.type] || 80;
const xpEarned = Math.round(baseXp * mult);

let streakLabel = '';
if (newStreak >= 30) streakLabel = 'Efsane';
else if (newStreak >= 14) streakLabel = 'Durdurulamaz';
else if (newStreak >= 7) streakLabel = 'Yaniyor';
else if (newStreak >= 3) streakLabel = 'Ateslendin';

// Fatigue hesapla — ard arda agir gun
const heavyTypes = ['Push','Pull','Bacak','Parkour','Akrobasi'];
const isHeavy = heavyTypes.includes(parsed.type);
let fatigue = profile.fatigue_current || 0;
if (isHeavy) fatigue = Math.min(100, fatigue + 25);
else fatigue = Math.max(0, fatigue - 15);

let armor = profile.armor_current || 100;
if (isHeavy && fatigue >= 75) armor = Math.max(0, armor - 10);
if (parsed.type === 'Stretching' || parsed.type === 'Yuruyus') armor = Math.min(100, armor + 12);

return [{ json: {
  ...parsed,
  xpEarned,
  xpMultiplier: mult,
  newStreak,
  streakLabel,
  profileId: profile.id,
  currentXp: profile.xp_current || 0,
  currentSessions: profile.sessions || 0,
  fatigue,
  armor,
  isHeavy
} }];
